namespace sv_4730fb0f5f514b9cac6c5d280b4d8f9f;

public class WizardState
{
    public PersonalInfo PersonalInfo { get; set; } = new();
    public List<ExperienceEntry> Experience { get; set; } = [];
    public List<ReferenceEntry> References { get; set; } = [];

    public int CurrentStep { get; private set; } = 1;
    public HashSet<int> CompletedSteps { get; } = [];

    public const int TotalSteps = 4;

    public event Action? OnChange;

    public void SetCurrentStep(int step)
    {
        CurrentStep = step;
        OnChange?.Invoke();
    }

    public void CompleteStep(int step)
    {
        CompletedSteps.Add(step);
        OnChange?.Invoke();
    }
}

public class PersonalInfo
{
    public string Name { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
}

public class ExperienceEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceEntry
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string ContactInfo { get; set; } = "";
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Step 1: Personal Info</PageTitle>

<h3>Personal Information</h3>

<EditForm Model="Wizard.PersonalInfo" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard.PersonalInfo.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard.PersonalInfo.Email" />
    </div>
    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText class="form-control" @bind-Value="Wizard.PersonalInfo.Phone" />
    </div>
    <button type="submit" class="btn btn-primary">Next: Experience →</button>
</EditForm>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(1);
    }

    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Step 2: Experience</PageTitle>

<h3>Work Experience</h3>

@foreach (var entry in Wizard.Experience)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="entry.Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input class="form-control" @bind="entry.Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="entry.Years" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(entry)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Experience</button>

<div>
    <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next: References →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(2);
        if (Wizard.Experience.Count == 0)
            AddEntry();
    }

    private void AddEntry() => Wizard.Experience.Add(new ExperienceEntry());
    private void RemoveEntry(ExperienceEntry entry) => Wizard.Experience.Remove(entry);
    private void Back() => Nav.NavigateTo("/apply/personal-info");

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Step 3: References</PageTitle>

<h3>References</h3>

@foreach (var entry in Wizard.References)
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="entry.Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="entry.Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Contact Info</label>
            <input class="form-control" @bind="entry.ContactInfo" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(entry)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Reference</button>

<div>
    <button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next: Review →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(3);
        if (Wizard.References.Count == 0)
            AddEntry();
    }

    private void AddEntry() => Wizard.References.Add(new ReferenceEntry());
    private void RemoveEntry(ReferenceEntry entry) => Wizard.References.Remove(entry);
    private void Back() => Nav.NavigateTo("/apply/experience");

    private void Next()
    {
        Wizard.CompleteStep(3);
        Nav.NavigateTo("/apply/review");
    }
}

@page "/apply/review"
@rendermode InteractiveServer
@inject WizardState Wizard

<PageTitle>Step 4: Review</PageTitle>

<h3>Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Wizard.PersonalInfo.Name</p>
    <p><strong>Email:</strong> @Wizard.PersonalInfo.Email</p>
    <p><strong>Phone:</strong> @Wizard.PersonalInfo.Phone</p>
</div>

<div class="card mb-3 p-3">
    <h5>Experience</h5>
    @foreach (var exp in Wizard.Experience)
    {
        <div class="mb-2">
            <strong>@exp.Title</strong> at @exp.Company (@exp.Years years)
        </div>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @foreach (var r in Wizard.References)
    {
        <div class="mb-2">
            <strong>@r.Name</strong> — @r.Relationship (@r.ContactInfo)
        </div>
    }
</div>

<button class="btn btn-secondary me-2" @onclick="Back">← Back</button>
<button class="btn btn-success" @onclick="Submit">Submit Application</button>

@code {
    [Inject] private NavigationManager Nav { get; set; } = default!;

    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(4);
    }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        Wizard.CompleteStep(4);
        // TODO: persist the application to a database here
        Nav.NavigateTo("/");
    }
}

