﻿@inherits LayoutComponentBase
@inject WizardState Wizard
@implements IDisposable

<div class="page">
    <div class="sidebar">
        <NavMenu />
    </div>

    <main>
        <div class="top-row px-4">
            @if (Wizard.CurrentStep >= 1 && Wizard.CurrentStep <= WizardState.TotalSteps)
            {
                <div class="wizard-progress me-auto d-flex align-items-center gap-2">
                    @for (int i = 1; i <= WizardState.TotalSteps; i++)
                    {
                        var step = i;
                        var css = Wizard.CompletedSteps.Contains(step)
                            ? "badge bg-success"
                            : step == Wizard.CurrentStep
                                ? "badge bg-primary"
                                : "badge bg-secondary";
                        <span class="@css">@step</span>
                    }
                    <span class="ms-2 text-muted">Step @Wizard.CurrentStep of @WizardState.TotalSteps</span>
                </div>
            }
            <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
        </div>

        <article class="content px-4">
            @Body
        </article>
    </main>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.OnChange += OnWizardChanged;
    }

    private void OnWizardChanged() => InvokeAsync(StateHasChanged);

    public void Dispose()
    {
        Wizard.OnChange -= OnWizardChanged;
    }
}

